import os
from pathlib import Path

def delete_uploaded_file(filename):
    """
    Delete a user's uploaded file from the 'uploads' directory.
    
    Args:
        filename (str): Name of the file to delete
        
    Returns:
        bool: True if file was deleted successfully, False otherwise
    """
    # Define the uploads directory
    uploads_dir = Path('uploads')
    
    # Create the uploads directory if it doesn't exist
    uploads_dir.mkdir(exist_ok=True)
    
    # Validate filename to prevent directory traversal attacks
    if '..' in filename or filename.startswith('/'):
        return False
    
    # Create the full file path
    file_path = uploads_dir / filename
    
    # Check if file exists and is within the uploads directory
    try:
        # Resolve the path to prevent directory traversal
        resolved_path = file_path.resolve()
        uploads_path = uploads_dir.resolve()
        
        # Ensure the file is within the uploads directory
        if uploads_path not in resolved_path.parents and resolved_path != uploads_path:
            return False
            
        # Check if file exists
        if file_path.exists() and file_path.is_file():
            file_path.unlink()
            return True
        return False
    except (OSError, PermissionError):
        return False